```php
<?php
// for : nombre d'itérations connu
for ($i = 0; $i < 5; $i++) {
    echo $i . " ";
}
echo "\n";  // 0 1 2 3 4

// while : condition d'arrêt
$n = 1;
while ($n <= 3) {
    echo "Tour $n\n";
    $n++;
}

// do...while : s'exécute au moins une fois
$x = 10;
do {
    echo "x = $x\n";
    $x--;
} while ($x > 8);

// foreach : parcourir un tableau
$fruits = ["pomme", "poire", "banane"];
foreach ($fruits as $fruit) {
    echo "- $fruit\n";
}

// foreach avec clé => valeur
$ages = ["Alice" => 28, "Bob" => 34];
foreach ($ages as $nom => $age) {
    echo "$nom a $age ans\n";
}

// break et continue
for ($i = 0; $i < 10; $i++) {
    if ($i === 5) break;     // stop
    if ($i % 2 === 0) continue;  // passe au suivant
    echo $i . " ";
}
echo "\n";  // 1 3
?>
